--
-- Table structure for table `user`
--

CREATE TABLE `user` (
  `id` int(11) NOT NULL,
  `email` varchar(191) NOT NULL,
  `password` varchar(191) DEFAULT NULL,
  `name` varchar(191) DEFAULT NULL,
  `role` enum('ADMIN','OWNER','TENANT') NOT NULL DEFAULT 'TENANT',
  `phone` varchar(191) DEFAULT NULL,
  `type` varchar(191) DEFAULT 'Individual',
  `createdAt` datetime(3) NOT NULL DEFAULT current_timestamp(3),
  `updatedAt` datetime(3) NOT NULL,
  `bedroomId` int(11) DEFAULT NULL,
  `buildingId` int(11) DEFAULT NULL,
  `companyDetails` text DEFAULT NULL,
  `companyName` varchar(191) DEFAULT NULL,
  `firstName` varchar(191) DEFAULT NULL,
  `inviteExpires` datetime(3) DEFAULT NULL,
  `inviteToken` varchar(191) DEFAULT NULL,
  `lastName` varchar(191) DEFAULT NULL,
  `unitId` int(11) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

